#include <bits/stdc++.h>
#define MAX (1000000 + 7)
using namespace std;

int N, K, T, a[MAX], f[MAX];
int L, R, Q[MAX];

int main() {
    scanf("%d", &N);
    for (int i = 1; i <= N; i++)
        scanf("%d", a + i);

    scanf("%d", &T);
    while (T--) {
        scanf("%d", &K);
        Q[L = R = 1] = 1;
        for (int i = 2; i <= N; i++) {
            while (L <= R && i - K > Q[L])
                L++;
            f[i] = f[Q[L]] + (a[Q[L]] <= a[i]);
            while (L <= R && (f[Q[R]] > f[i] || (f[Q[R]] == f[i] && a[Q[R]] <= a[i])))
                R--;
            Q[++R] = i;
        }
        printf("%d\n", f[N]);
    }
}
